const express = require('express');
const bodyParser = require('body-parser');
const naturalLanguageUnderstanding = require('natural-language-understanding');
const { exec } = require('child_process');

const app = express();
app.use(bodyParser.json());

// Set up Natural Language Understanding service
const nlu = new naturalLanguageUnderstanding({
  version: '2019-07-12',
  url: 'https://api.us-south.natural-language-understanding.watson.cloud.ibm.com/instances/<instance_id>',
  username: '<username>',
  password: '<password>'
});

// Set up LLM model for code generation
const lm = new LanguageModel('path/to/model');

app.post('/generate-code', (req, res) => {
  const description = req.body.description;
  const prompt = `Generate code for ${description}`;

  // Send prompt to AI model and execute generated code
  lm.execute(prompt).then((result) => {
    const code = result.code;
    exec(code, (err, stdout, stderr) => {
      if (err) {
        console.error(`Error executing code: ${err}`);
        res.status(500).send('Error generating code');
      } else {
        res.json({ code });
      }
    });
  }).catch((err) => {
    console.error(`Error generating code: ${err}`);
    res.status(500).send('Error generating code');
  });
});

app.listen(3000, () => {
  console.log('Server started on port 3000');
});